func (f *FileLogger) Log(msg string) { /* ... */ }

func ProcessA(path string) {
    var logger *FileLogger
    if path != "" {
        logger = &FileLogger{path: path}
    }
    if logger == nil {
        return
    }
    logger.Log("starting")
}
```

Version B (refactored to return via interface):
```go
type Logger interface {
    Log(msg string)
}

func NewFileLogger(path string) Logger {
    if path == "" {
        var l *FileLogger = nil
        return l
    }
    return &FileLogger{path: path}
}

func ProcessB(path string) {
    logger := NewFileLogger(path)
    if logger == nil {
        return
    }
    logger.Log("starting")
}
```

