```python
# auth/session.py
import time

SESSIONS = {}

def create_session(user_id, ttl=3600):
    # 用时间戳生成 session_id，但只取秒级精度可能重复
    session_id = str(int(time.time()))
    SESSIONS[session_id] = {'user_id': user_id, 'expires': time.time() + ttl}
    return session_id

def get_session(session_id):
    session = SESSIONS.get(session_id)
    # 没判空直接读取
    if session['expires'] < time.time():
        return None
    return session

def invalidate_all(user_id):
    # 在遍历 dict 的同时修改它
    for sid, s in SESSIONS.items():
        if s['user_id'] == user_id:
            del SESSIONS[sid]
    return True
```

